export type LineupGenerateInputRaceFormat = typeof LineupGenerateInputRaceFormat[keyof typeof LineupGenerateInputRaceFormat];


export const LineupGenerateInputRaceFormat = {
  one_moto: 'one_moto',
  two_moto: 'two_moto',
  three_moto: 'three_moto',
} as const;

/**
 * Controls how riders are ordered into gate positions. random = shuffle randomly (default); practice_fastest_lap = sort by best practice lap time (fastest gets best pick); previous_round = sort by finish position in the most recently completed round, tiebroken by fastest lap time in that round. When omitted, defaults to random (preserving backward compatibility).

 */
export type LineupGenerateInputGateSeedingMethod = typeof LineupGenerateInputGateSeedingMethod[keyof typeof LineupGenerateInputGateSeedingMethod];


export const LineupGenerateInputGateSeedingMethod = {
  random: 'random',
  practice_fastest_lap: 'practice_fastest_lap',
  previous_round: 'previous_round',
} as const;

/**
 * Controls gate number assignment. random = riders shuffled randomly, gates assigned in configured priority order; practice = sort by best practice lap time (fastest gets first gate pick); prior_round_finish = sort by prior round finish position, best finisher picks first; first_registered = sort by registration timestamp, earliest registered gets first gate pick. Supersedes gateSeedingMethod when both are present.

 */
export type LineupGenerateInputGatePickMethod = typeof LineupGenerateInputGatePickMethod[keyof typeof LineupGenerateInputGatePickMethod];


export const LineupGenerateInputGatePickMethod = {
  random: 'random',
  practice: 'practice',
  prior_round_finish: 'prior_round_finish',
  first_registered: 'first_registered',
} as const;

export interface LineupGenerateInput {
  raceFormat: LineupGenerateInputRaceFormat;
  classes: string[];
  ridersPerHeat?: number;
  /** Deprecated: use gateSeedingMethod instead. Still accepted for backward compatibility. */
  usePracticeSeeding?: boolean;
  /** Controls how riders are ordered into gate positions. random = shuffle randomly (default); practice_fastest_lap = sort by best practice lap time (fastest gets best pick); previous_round = sort by finish position in the most recently completed round, tiebroken by fastest lap time in that round. When omitted, defaults to random (preserving backward compatibility).
   */
  gateSeedingMethod?: LineupGenerateInputGateSeedingMethod;
  /** If provided, only generate motos for these round numbers (1-indexed). Omit or leave empty to regenerate all rounds. Motos from unspecified rounds are left untouched.
   */
  rounds?: number[];
  /** Controls gate number assignment. random = riders shuffled randomly, gates assigned in configured priority order; practice = sort by best practice lap time (fastest gets first gate pick); prior_round_finish = sort by prior round finish position, best finisher picks first; first_registered = sort by registration timestamp, earliest registered gets first gate pick. Supersedes gateSeedingMethod when both are present.
   */
  gatePickMethod?: LineupGenerateInputGatePickMethod;
  /** Race time limit in milliseconds. When set, the race runs until this duration expires, then plusLaps additional laps are counted before the moto ends. Mutually exclusive with lapCount (time-based vs laps-based).
   */
  timeLimitMs?: number;
  /** Number of additional laps riders complete after the time limit expires. Defaults to 1 (classic "time + 1 lap" motocross format). Only meaningful when timeLimitMs is also set.
   */
  plusLaps?: number;
  /** Number of laps for each generated moto. When set, indicates this is a laps-based race (first to reach this many laps wins) and the value is stored on every created moto for display and timing purposes.
   */
  lapCount?: number;
  /**
     * Minimum number of races that must separate a rider's consecutive motos when they are entered in multiple classes. The scheduler will try to reorder classes in the run order to satisfy this constraint. If it cannot fully satisfy the constraint, motos are still created and the remaining conflicts are surfaced in the response header.

     * @minimum 1
     * @maximum 3
     */
  minRacesBetween?: number;
  /** When true, generate lineup slots for all registered riders (not only those who have checked in). Riders who have not yet checked in appear in the lineup with checkedIn: false. When a rider later checks in, their slot is automatically updated to checkedIn: true.
   */
  useRegistrations?: boolean;
}

/**
 * Gate pick method for this specific moto. random = random gate draw; practice = by practice lap time; prior_round_finish = by prior round finish position; first_registered = earliest registered rider gets first gate pick.

 */
export type GenerateMotoLineupInputGatePickMethod = typeof GenerateMotoLineupInputGatePickMethod[keyof typeof GenerateMotoLineupInputGatePickMethod];


export const GenerateMotoLineupInputGatePickMethod = {
  random: 'random',
  practice: 'practice',
  prior_round_finish: 'prior_round_finish',
  first_registered: 'first_registered',
} as const;

export interface GenerateMotoLineupInput {
  /** Gate pick method for this specific moto. random = random gate draw; practice = by practice lap time; prior_round_finish = by prior round finish position; first_registered = earliest registered rider gets first gate pick.
   */
  gatePickMethod?: GenerateMotoLineupInputGatePickMethod;
}

